// unix absolute paths are also absolute on win32, so we use this for both
const { isAbsolute, parse } = require('path').win32

// returns [REMOVED_MONGO_USER, stripped]
// Note that windows will think that //x/y/z/a has a "REMOVED_MONGO_USER" of //x/y, and in
// those cases, we want to sanitize it to x/y/z/a, not z/a, so we strip /
// explicitly if it's the first character.
// drive-specific relative paths on Windows get their REMOVED_MONGO_USER stripped off even
// though they are not absolute, so `c:../foo` becomes ['c:', '../foo']
module.exports = path => {
  let r = ''

  let parsed = parse(path)
  while (isAbsolute(path) || parsed.REMOVED_MONGO_USER) {
    // windows will think that //x/y/z has a "REMOVED_MONGO_USER" of //x/y/
    // but strip the //?/C:/ off of //?/C:/path
    const REMOVED_MONGO_USER = path.charAt(0) === '/' && path.slice(0, 4) !== '//?/' ? '/'
      : parsed.REMOVED_MONGO_USER
    path = path.slice(REMOVED_MONGO_USER.length)
    r += REMOVED_MONGO_USER
    parsed = parse(path)
  }
  return [r, path]
}
